conn = sqlite3.connect('career_db.sqlite')
c = conn.cursor()

for pid, (title, desc, category, skills, opps) in kk_professions.items():
    c.execute(
        'UPDATE professions SET title=?, description=?, category=?, required_skills=?, future_opportunities=? WHERE id=?',
        (title, desc, category,
         json.dumps(skills, ensure_ascii=False),
         json.dumps(opps, ensure_ascii=False),
         pid)
    )

conn.commit()
conn.close()
print(f'Restored {len(kk_professions)} Kazakh professions')
print('Done!')
